const keyword = $('Batch Keywords').item.json;
const searchResults = $input.item.json;
const items = searchResults.items || [];

let rank = null;
let rankUrl = null;

for (let i = 0; i < items.length; i++) {
  const link = items[i].link || '';
  if (link.includes(keyword.domain)) {
    rank = i + 1;
    rankUrl = link;
    break;
  }
}

return [{
  json: {
    keyword_id: keyword.id,
    keyword: keyword.keyword,
    client_id: keyword.client_id,
    domain: keyword.domain,
    rank: rank,
    url: rankUrl,
    serp_features: items.slice(0, 3).map(i => i.link)
  }
}];
